import { useState } from "react"
import './App.css';
import { InputTodo } from "./components/InputTodo";
import { IncompleteTodos } from "./components/IncompleteTodos"
import { CompleteTodos } from "./components/CompleteTodos";
import { ChakraProvider, Flex, Box } from "@chakra-ui/react"
import theme from "./theme/theme"

export const TodoList = () => {
  const [todoText, settodoText] = useState("");
  const [incompleteTodos, setincompleteTodos] = useState([]);
  const [completeTodos, setcompleteTodos] = useState([]);
  const [inputCardTitle, setInputCardTitle] = useState();
  const items = [];

  const onChangeTodoText = (e) => settodoText(e.target.value);

  const onClickAdd = () => {
    if (todoText === "") return;
    const newTodo = { text: todoText, isEditing: false };
    const newTodos = [...incompleteTodos, newTodo];
    setincompleteTodos(newTodos);
    settodoText("");
    items.push(newTodo);
    console.log(newTodos);
    console.log(newTodos.length);
  }

  const onClickDelete = (index) => {
    // 削除する前に確認のポップアップを表示
    let result = window.confirm("本当に削除してもよろしいですか？");
    if (result) {
    const newTodos = [...incompleteTodos];
    newTodos.splice(index, 1);
    setincompleteTodos(newTodos);
    }
  }

  const onClickComplete = (index) => {
    const newIncompleteTodos = [...incompleteTodos];
    newIncompleteTodos.splice(index, 1);

    const newCompleteTodos = [...completeTodos, incompleteTodos[index]];
    console.log(newCompleteTodos);
    setincompleteTodos(newIncompleteTodos);
    setcompleteTodos(newCompleteTodos);
  }

  const onClickBack = (index) => {
    const newCompleteTodos = [...completeTodos];
    newCompleteTodos.splice(index, 1);

    const newIncompleteTodos = [...incompleteTodos, completeTodos[index]];
    setcompleteTodos(newCompleteTodos);
    setincompleteTodos(newIncompleteTodos);
  }


  const handleClick = (index) => {
    // 編集対象のタスクを初期値に設定
    const selectedTodo = incompleteTodos[index];
    setInputCardTitle(selectedTodo.text);
    const updateTodos = incompleteTodos.map((todo, i) => {
      if (i === index) {
        return { ...todo, isEditing: !todo.isEditing };
      } else{
        return todo;
      }
    });
    setincompleteTodos(updateTodos);
  }

  const handleChange = (e) => {
    setInputCardTitle(e.target.value);
  }

  const handleSubmit = (index, e) => {
    e.preventDefault();
    const updateTodos = incompleteTodos.map((todo, i) => {
      if (i === index) {
        return { ...todo, text: inputCardTitle, isEditing: false};
      } else {
        return todo;
      }
    });
    setincompleteTodos(updateTodos);
  }



  return (
    <>
      <ChakraProvider theme={theme}>
      <Flex h={200} justify='center' align='center' bg='gray.100' >
        <InputTodo 
          todoText={todoText} 
          onChange={onChangeTodoText} 
          onClick={onClickAdd}
        />
        </Flex>
        <Box>
        <div>
          <div>全てのタスク： {items.length} 完了済み：2 未完了：1</div>
        <p>未完了のToDo</p>
        <ul>
          {incompleteTodos.map((todo, index) => (
          <li key={index}>
            <Box display="flex" p={2}>
            <input type="checkbox" onChange={() => onClickComplete(index)}/>
                      <div>
                {todo.isEditing ? (
                    <form onSubmit={(e) => handleSubmit(index, e)}>
                      <input 
                        id="todo" 
                        type="text"
                        value={inputCardTitle}
                        onChange={handleChange}/>
                      <button type="submit">Save</button>
                    </form>
                      )
                   : (
                    <div>
                     <p>{todo.text}</p>
                      <button onClick={() => handleClick(index)}>Edit</button>
                      </div>
                   )}
              </div>
            <Box px={2}>
            </Box>
            <button onClick={() => onClickDelete(index)}>削除</button>
            </Box>
          </li>
            )
        )}
        </ul>
    </div>
        </Box>
        <CompleteTodos 
          completeTodos={completeTodos}
          onClickBack={onClickBack}
        />
      </ChakraProvider>
    </>
  );
};
